import{_ as a,c as t,o as s,a1 as o}from"./chunks/framework.DDNAyvCW.js";const n="/assets/mobile_asset.CJfe4MIm.jpg",p=JSON.parse('{"title":"Asset Management","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/assets/index.md","filePath":"docs/mobile/assets/index.md"}'),r={name:"docs/mobile/assets/index.md"};function i(d,e,l,c,h,u){return s(),t("div",null,e[0]||(e[0]=[o('<h1 id="asset-management" tabindex="-1">Asset Management <a class="header-anchor" href="#asset-management" aria-label="Permalink to &quot;Asset Management&quot;">​</a></h1><p>The Assets module is the mobile entry point for managing SSH resources. It includes Direct Connection, Bastion Resources, and Key Management.</p><div style="text-align:center;"><img src="'+n+'" alt="AI Dialog mobile page" width="320"></div><h2 id="direct-connections" tabindex="-1">Direct Connections <a class="header-anchor" href="#direct-connections" aria-label="Permalink to &quot;Direct Connections&quot;">​</a></h2><p>Direct Connections are used for servers you add yourself.</p><h3 id="add-a-new-asset" tabindex="-1">Add a New Asset <a class="header-anchor" href="#add-a-new-asset" aria-label="Permalink to &quot;Add a New Asset&quot;">​</a></h3><p>Tap <code>+</code> in the lower-right corner → <strong>New</strong>, fill in the server details, and save.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Label</td><td>A recognizable name, e.g. <code>prod-web-01</code></td></tr><tr><td>IP / Domain</td><td>Server address</td></tr><tr><td>Port</td><td>Default <code>22</code></td></tr><tr><td>Username</td><td>Login user, e.g. <code>root</code>, <code>ubuntu</code></td></tr><tr><td>Authentication</td><td><strong>Password</strong>: enter directly; <strong>Key</strong>: import in <a href="#key-management">Key Management</a> first</td></tr></tbody></table><h3 id="manage-assets" tabindex="-1">Manage Assets <a class="header-anchor" href="#manage-assets" aria-label="Permalink to &quot;Manage Assets&quot;">​</a></h3><ul><li>Connect: tap a host card to open an SSH session</li><li>Edit: long-press a card and choose <code>Edit</code></li><li>Favorite: long-press a card and choose <code>Favorite</code> to pin it near the top</li><li>Delete: long-press a card and choose <code>Delete</code></li></ul><h3 id="recent-connection-sorting" tabindex="-1">Recent Connection Sorting <a class="header-anchor" href="#recent-connection-sorting" aria-label="Permalink to &quot;Recent Connection Sorting&quot;">​</a></h3><p>The host list is automatically sorted by last connection time, so the most recently used hosts appear at the top for quick access.</p><h3 id="search-and-filter" tabindex="-1">Search and Filter <a class="header-anchor" href="#search-and-filter" aria-label="Permalink to &quot;Search and Filter&quot;">​</a></h3><p>You can search or filter by:</p><ul><li>Host name</li><li>IP address</li><li>Username</li><li>Group</li></ul><h2 id="bastion-resources" tabindex="-1">Bastion Resources <a class="header-anchor" href="#bastion-resources" aria-label="Permalink to &quot;Bastion Resources&quot;">​</a></h2><p>Bastion Resources are used to manage server assets maintained behind a jump server.</p><h3 id="add-a-bastion-resource" tabindex="-1">Add a Bastion Resource <a class="header-anchor" href="#add-a-bastion-resource" aria-label="Permalink to &quot;Add a Bastion Resource&quot;">​</a></h3><ol><li>Tap <code>+</code></li><li>Choose <code>New</code></li><li>Fill in the bastion host name, address, port, and username</li><li>Choose key-based authentication</li><li>Tap <code>Save and Sync</code></li></ol><p>After saving, the synced server assets appear in the bastion host drop-down list.</p><h3 id="manage-bastion-resources" tabindex="-1">Manage Bastion Resources <a class="header-anchor" href="#manage-bastion-resources" aria-label="Permalink to &quot;Manage Bastion Resources&quot;">​</a></h3><ul><li>Sync assets: tap the sync button next to the group title</li><li>Edit: long-press the group name and choose <code>Edit</code></li><li>Delete: long-press the group name and choose <code>Delete</code></li></ul><h3 id="manage-synced-server-assets" tabindex="-1">Manage Synced Server Assets <a class="header-anchor" href="#manage-synced-server-assets" aria-label="Permalink to &quot;Manage Synced Server Assets&quot;">​</a></h3><p>Synced assets under a bastion host support these actions:</p><ul><li>Tap a card to connect</li><li>Long-press a card to edit notes</li><li>Long-press a card to add it to favorites</li></ul><h2 id="key-management" tabindex="-1">Key Management <a class="header-anchor" href="#key-management" aria-label="Permalink to &quot;Key Management&quot;">​</a></h2><p>Key Management is used to maintain the SSH keys required for login.</p><ul><li>Tap the lower-right <code>+</code> button to add a new key</li><li>Import key files from local storage</li><li>Use the edit and delete actions shown on each key card</li></ul><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>If you manage many hosts, keep favorites, groups, and notes organized first. It makes searching much faster.</p></div>',29)]))}const g=a(r,[["render",i]]);export{p as __pageData,g as default};
